import React, { useState } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

const Login = () => {
  const { login } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const from = location.state?.from?.pathname || "/";

  const [form, setForm] = useState({ email: "", password: "" });
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [apiError, setApiError] = useState("");

  const validate = () => {
    const next = {};
    if (!form.email) next.email = "Email is required";
    else if (!/\S+@\S+\.\S+/.test(form.email)) next.email = "Invalid email format";
    if (!form.password) next.password = "Password is required";
    else if (form.password.length < 6) next.password = "Minimum 6 characters";
    return next;
  };

  const onChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setErrors({ ...errors, [e.target.name]: "" });
    setApiError("");
  };

  const onSubmit = async (e) => {
    e.preventDefault();
    const nextErrors = validate();
    if (Object.keys(nextErrors).length) {
      setErrors(nextErrors);
      return;
    }

    setLoading(true);
    try {
      await login(form);
      navigate(from, { replace: true });
    } catch (err) {
      setApiError(err.response?.data?.message || "Login failed. Check your credentials.");
    } finally {
      setLoading(false);
    }
  };

  const inputStyle = (field) => ({
    borderColor: errors[field] ? "rgba(251,113,133,0.45)" : "var(--border)",
  });

  return (
    <div className="auth-shell">
      <div className="auth-side d-none d-lg-flex flex-column justify-content-between">
        <div>
          <Link to="/" className="navbar-brand d-inline-flex align-items-center gap-3 fw-bold mb-5">
            <span
              className="d-inline-flex align-items-center justify-content-center"
              style={{ width: 40, height: 40, borderRadius: 14, background: "rgba(96,165,250,0.12)", border: "1px solid rgba(96,165,250,0.18)", color: "var(--primary)", fontFamily: "var(--font-mono)" }}
            >
              CL
            </span>
            <span>CodeLearn</span>
          </Link>
          <span className="eyebrow mb-4">Continue learning</span>
          <h1 className="section-heading mb-3" style={{ fontSize: "clamp(2.4rem, 4vw, 3.6rem)" }}>
            Return to your course flow.
          </h1>
          <p className="section-copy mb-4">
            Pick up your lessons, review completed work, and keep your learning streak moving without distraction.
          </p>
          <div className="feature-list">
            {[
              "Access enrolled courses instantly",
              "See progress across each lesson track",
              "Resume exactly where you stopped",
            ].map((feature) => (
              <div key={feature} className="feature-item">
                <div className="feature-icon">
                  <i className="bi bi-check2" />
                </div>
                <div style={{ color: "var(--text-secondary)" }}>{feature}</div>
              </div>
            ))}
          </div>
        </div>
        <div className="surface-card p-4" style={{ boxShadow: "none" }}>
          <div style={{ color: "var(--text-muted)", textTransform: "uppercase", letterSpacing: "0.12em", fontSize: "0.74rem", fontWeight: 700 }} className="mb-2">
            Member access
          </div>
          <div className="fw-bold mb-1">Course history, lesson tracking, and saved progress.</div>
          <div style={{ color: "var(--text-secondary)" }}>Built for focused learning sessions on desktop and mobile.</div>
        </div>
      </div>

      <div className="auth-form-wrap">
        <div className="auth-card">
          <div className="mb-4">
            <div style={{ color: "var(--text-muted)", textTransform: "uppercase", letterSpacing: "0.12em", fontSize: "0.74rem", fontWeight: 700 }} className="mb-2">
              Log in
            </div>
            <h2 className="fw-bold mb-2">Welcome back</h2>
            <p style={{ color: "var(--text-secondary)", margin: 0 }}>
              New here? <Link to="/signup" style={{ color: "var(--primary)", fontWeight: 700 }}>Create an account</Link>
            </p>
          </div>

          {apiError && (
            <div className="alert mb-4" style={{ background: "rgba(251,113,133,0.1)", border: "1px solid rgba(251,113,133,0.3)", color: "var(--danger)", borderRadius: 18 }}>
              {apiError}
            </div>
          )}

          <form onSubmit={onSubmit} noValidate>
            <div className="mb-3">
              <label className="form-label small fw-bold" style={{ color: "var(--text-secondary)" }}>
                Email Address
              </label>
              <input type="email" name="email" className="form-control" placeholder="you@example.com" value={form.email} onChange={onChange} style={inputStyle("email")} />
              {errors.email && <div className="mt-2 small" style={{ color: "var(--danger)" }}>{errors.email}</div>}
            </div>

            <div className="mb-4">
              <label className="form-label small fw-bold" style={{ color: "var(--text-secondary)" }}>
                Password
              </label>
              <input type="password" name="password" className="form-control" placeholder="Minimum 6 characters" value={form.password} onChange={onChange} style={inputStyle("password")} />
              {errors.password && <div className="mt-2 small" style={{ color: "var(--danger)" }}>{errors.password}</div>}
            </div>

            <button type="submit" className="btn btn-primary-custom w-100 py-3" disabled={loading}>
              {loading ? (
                <>
                  <span className="spinner-border spinner-border-sm me-2" />
                  Logging in...
                </>
              ) : (
                "Log In"
              )}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Login;
